base = r"C:\Users\2121\AppData\Roaming\TRAE SOLO CN\ModularData\ai-agent\work-mode-projects\6a3ed37f1ac00f6e4879b1bd\chronos-app\public\data\narratives"

wentianxiang = {"eraId":"song-yuan","eraName":"宋元","playerRole":"文天祥","acts":[{"id":"act-1","title":"状元及第","isKeyAct":False,"sceneDescription":"南宋理宗宝祐四年，庐陵青年文天祥赴京参加殿试。他一篇洋洋万言的策论直陈时弊，针砭南宋朝政的腐败和军事的衰弱。宋理宗读后大为赞叹，钦点他为状元。然而这位新科状元心中没有多少喜悦，因为他看到的是一个千疮百孔的王朝。","npcDialogues":[{"speaker":"宋理宗","text":"这篇文章写得极好！直陈时弊，不畏权贵。此人有状元之才，更有宰相之志！","avatar":"理"},{"speaker":"同考官","text":"这位文天祥的文章虽然犀利了些，但字字珠玑，切中要害。陛下龙颜大悦啊。","avatar":"考"}],"dialogues":[{"id":"d1","text":"陛下，臣这篇策论句句肺腑之言。大宋积弊已深，若不彻底改革，恐怕危亡不远了！","speaker":"我","avatar":"祥","score":92,"triggeredEvent":"状元直言","historicalNote":"文天祥殿试时以万言策论直陈时弊，针砭南宋政治腐败和军事衰弱。理宗钦点他为状元，但他的建议并未被朝廷采纳。","consequence":"你被钦点为状元，名动天下。但你的直言也引起了一些权贵的不满。你暗下决心，要在朝中推行改革。"},{"id":"d2","text":"得中状元固然高兴，但我更关心的是这篇文章能否引起朝廷的重视，真正解决问题。","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"忧国忧民","historicalNote":"文天祥一生忧国忧民，他虽然位极人臣，但从不追求个人荣华，而是始终以国事为重。","consequence":"你的忧国忧民之心赢得了正直之士的赞赏。但你深知，一篇文章不足以改变整个朝廷的腐败。"},{"id":"d3","text":"我要利用状元的身份，广交有志之士，共同为国家的未来谋划。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"广交志士","historicalNote":"文天祥确实利用自己的名声和地位，团结了一批有志之士，后来在抗元斗争中发挥了重要作用。","consequence":"你结交了一批志同道合的仁人志士，为日后的抗元斗争储备了力量。"},{"id":"d4","text":"我虽然是新科状元，但在朝廷中毫无根基，要先站稳脚跟才行。","speaker":"我","avatar":"祥","score":78,"triggeredEvent":"立足朝堂","historicalNote":"文天祥在朝中确实面临着根基浅薄的问题，他的改革主张常常受到既得利益者的阻挠。","consequence":"你开始在朝中小心翼翼地建立自己的根基，同时学习朝廷的运作方式。"},{"id":"d5","text":"我要回庐陵看望父母和老师，感谢他们的养育和教诲之恩。","speaker":"我","avatar":"祥","score":82,"triggeredEvent":"感恩故里","historicalNote":"文天祥是一个重视孝道的人，他在做官后仍经常回乡看望父母。他的母亲和老师对他的影响深远。","consequence":"你回到庐陵看望家人和恩师，在家乡受到了热烈的欢迎。父母和老师的教诲你铭记在心。"},{"id":"d6","text":"我要趁年轻多学习一些军事知识，将来如果边关有急，我也能为国出征。","speaker":"我","avatar":"祥","score":83,"triggeredEvent":"学习军事","historicalNote":"文天祥虽然出身文官，但他后来确实组织了义军抗击元军，展现了出色的军事才能。","consequence":"你开始学习军事知识，为将来可能的战事做准备。这种远见在后来证明是非常有必要的。"}],"nextActId":"act-2"},{"id":"act-2","title":"起兵抗元","isKeyAct":True,"sceneDescription":"德祐二年，元军大举南下，南宋朝廷岌岌可危。朝廷下诏各地勤王，但响应者寥寥。你接到诏书后，立即变卖家产，招募义军，组织了一支万人的抗元队伍。朋友们劝你保存实力，但你义无反顾。国家危亡之际，匹夫有责！","npcDialogues":[{"speaker":"好友","text":"天祥，朝廷已经半壁江山尽失，勤王有什么用？你何不保存实力，另寻出路？","avatar":"友"},{"speaker":"部将","text":"文大人，我们虽然人数不多，但都是热血男儿，愿意跟您一起保家卫国！","avatar":"将"}],"dialogues":[{"id":"d1","text":"国破山河碎，我身为大宋臣子，岂能坐视不理？我变卖家产，招募义军，誓与国家共存亡！","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"散财聚兵","historicalNote":"文天祥接到勤王诏书后变卖家产，招募义军万人，入卫临安。他的行为在当时极为罕见，展现了惊人的爱国热情。","consequence":"你变卖家产，招募了一万名义军。这支队伍虽然装备简陋，但士气高昂。你率领他们向临安进发。"},{"id":"d2","text":"敌人强大，我们不能正面硬拼。要采取灵活的战术，保存实力，伺机反击。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"灵活战术","historicalNote":"文天祥虽然不是职业军人，但在抗元斗争中展现了出色的战略头脑。他多次采用灵活的战术打击元军。","consequence":"你采取了灵活的游击战术，避免与元军正面交锋，同时不断骚扰敌人后方。这种战术在一定程度上牵制了元军的进攻。"},{"id":"d3","text":"我号召各地忠义之士加入抗元义军。只要人心不死，大宋就不会亡！","speaker":"我","avatar":"祥","score":90,"triggeredEvent":"号召义军","historicalNote":"文天祥的抗元号召虽然响应者不多，但他的行动极大地鼓舞了南宋军民的抗战意志。","consequence":"你的号召在江南各地引起了强烈反响，不少爱国志士纷纷加入。虽然总兵力有限，但抗战的士气得到了极大的鼓舞。"},{"id":"d4","text":"我要先稳固江南的防线，确保后方安全，然后伺机北进，收复失地。","speaker":"我","avatar":"祥","score":82,"triggeredEvent":"稳固后方","historicalNote":"文天祥在抗元斗争中确实注重巩固后方，同时积极组织抵抗力量。","consequence":"你着手巩固江南防线，建立了一套有效的防御体系。虽然无法阻止元军的推进，但为南宋争取了宝贵的时间。"},{"id":"d5","text":"朝廷虽然腐败，但只要还有一线希望，我就会坚持抗元到底！","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"坚持抗战","historicalNote":"文天祥在南宋朝廷投降后仍然坚持抗元，这种不屈精神成为后世最崇高的爱国典范。","consequence":"你坚定地表达了抗战到底的决心。即使在朝廷投降后，你仍然没有放弃。"},{"id":"d6","text":"朋友们劝我保存实力，但民族大义面前，个人安危算得了什么？","speaker":"我","avatar":"祥","score":92,"triggeredEvent":"舍身为国","historicalNote":"文天祥在国难当头时选择了舍身为国，放弃了个人安逸的生活。这种牺牲精神感动了后世无数人。","consequence":"你毅然放弃了安逸的生活，全身心投入到抗元斗争中。你的选择感动了身边的每一个人。"}],"nextActId":"act-3"},{"id":"act-3","title":"转战江西","isKeyAct":False,"sceneDescription":"南宋朝廷投降后，你拥立端宗赵昰在福建继续抗元。你率军在江西、广东一带与元军周旋，虽然屡战屡败，但你始终没有放弃。在兴国、赣州一带，你组织了多次反攻，虽然规模不大，但极大地鼓舞了南方军民的士气。","npcDialogues":[{"speaker":"陆秀夫","text":"文丞相，朝廷虽然南迁，但士气未散。只要我们坚持抵抗，复国仍有希望！","avatar":"秀"},{"speaker":"部将","text":"丞相，元军追得紧，我们的粮草已经不多了。怎么办？","avatar":"将"}],"dialogues":[{"id":"d1","text":"即使朝廷南迁，我也要在敌后坚持游击，牵制元军兵力，为南方争取时间！","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"敌后游击","historicalNote":"文天祥在南宋投降后确实在江西、广东一带进行了长期的敌后游击战，有效地牵制了元军的力量。","consequence":"你在敌后开展游击战争，不断骚扰元军后方。虽然战果有限，但极大地鼓舞了南方军民的抗战意志。"},{"id":"d2","text":"粮草不足，我们就向当地百姓借粮，同时发动百姓参与抗元。人民的力量是无穷的！","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"发动百姓","historicalNote":"文天祥在抗元斗争中确实发动了大量百姓参与，这在一定程度上弥补了军队兵力的不足。","consequence":"你发动当地百姓参与抗元斗争，建立了军民一体的抵抗体系。人民的支持让你的队伍在困境中得以存续。"},{"id":"d3","text":"我虽然在战场上屡次失败，但每一次失败都让我更加坚强。败而不馁，这就是我的信念。","speaker":"我","avatar":"祥","score":82,"triggeredEvent":"败而不馁","historicalNote":"文天祥在抗元斗争中确实屡战屡败，但他从不气馁。这种百折不挠的精神是他最打动后世的品质之一。","consequence":"你在一次次失败中总结经验，越挫越勇。你的不屈精神感染了每一个战友。"},{"id":"d4","text":"我派人联络各地的抗元力量，建立统一的指挥体系。分散的力量必须联合起来。","speaker":"我","avatar":"祥","score":80,"triggeredEvent":"联络各方","historicalNote":"文天祥确实试图联络各地抗元力量建立统一战线，但由于各路义军互不统属，效果有限。","consequence":"你努力联络各方抗元力量，虽然未能建立完全统一的指挥体系，但在一定程度上协调了各路的行动。"},{"id":"d5","text":"端宗年幼，我作为丞相要辅佐幼主，同时指挥军事。身兼数职，责任重大。","speaker":"我","avatar":"祥","score":83,"triggeredEvent":"辅佐幼主","historicalNote":"文天祥在南迁后担任丞相，辅佐年幼的端宗和赵昺。他既管政务又管军事，负担极重。","consequence":"你在辅佐幼主的同时指挥军事，虽然疲于奔命，但始终没有放弃复国的信念。"},{"id":"d6","text":"不管局势多么艰难，我都要坚持在江南抗战。这里是汉人的故土，决不能轻易放弃！","speaker":"我","avatar":"祥","score":86,"triggeredEvent":"坚守江南","historicalNote":"文天祥在江西、广东一带坚持抗元，即使在小朝廷覆灭后仍不屈服。他的坚持成为后世最崇高的爱国象征。","consequence":"你在江南坚持抗战，即使处境越来越困难，你也从未动摇。你的坚持让元军始终无法安心占领南方。"}],"nextActId":"act-4"},{"id":"act-4","title":"兵败被俘","isKeyAct":True,"sceneDescription":"五坡岭之战，你率残部与元军激战，最终兵败被俘。元军将领张弘范要你写信劝降南宋残余势力，你严词拒绝。在押送途中，你途经零丁洋，写下了千古绝唱《过零丁洋》。诗中有你一生的悲壮，也有一个民族英雄最后的宣言。","npcDialogues":[{"speaker":"张弘范","text":"文丞相，大宋已经亡了。你何必再苦苦支撑？只要你归顺元朝，必定受到重用。","avatar":"张"},{"speaker":"元军将领","text":"此人宁死不降，真是硬骨头。把他押到大都去，交给陛下处置！","avatar":"元"}],"dialogues":[{"id":"d1","text":"人生自古谁无死，留取丹心照汗青！我文天祥生是大宋的臣子，死是大宋的鬼魂，绝不会向你们投降！","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"过零丁洋","historicalNote":"文天祥在被俘后写下了《过零丁洋》，'人生自古谁无死，留取丹心照汗青'成为千古绝唱，是中国历史上最伟大的爱国诗篇之一。","consequence":"你的《过零丁洋》传遍天下。'人生自古谁无死，留取丹心照汗青'成为中华民族精神的不朽丰碑。元军将领读后也不得不敬佩你的气节。"},{"id":"d2","text":"你让我写信劝降？好，我给你写一首诗！","speaker":"我","avatar":"祥","score":90,"triggeredEvent":"诗代降书","historicalNote":"张弘范逼迫文天祥写信劝降张世杰，文天祥写下了《过零丁洋》作为回答。张弘范读后叹道'好人好诗'。","consequence":"你以诗代信，将劝降信变成了千古绝唱。张弘范读后也不得不感叹你的才华和气节。"},{"id":"d3","text":"大宋虽然亡了，但只要还有一个人在抵抗，大宋的精神就没有死。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"精神不灭","historicalNote":"文天祥在被俘后始终不肯投降，他坚信民族精神不灭。这种信念支撑他度过了三年的牢狱生涯。","consequence":"你的话深深感染了身边的人。即使在国家灭亡的时刻，你的精神仍然激励着无数人。"},{"id":"d4","text":"我被俘了，但我绝不吃元军的饭。我要绝食抗议，以死明志！","speaker":"我","avatar":"祥","score":82,"triggeredEvent":"绝食抗议","historicalNote":"文天祥被俘后确实曾绝食抗议，但被元军强行灌食。他在狱中始终保持着不屈的意志。","consequence":"你绝食以明志，但被元军强行制止。你在肉体上的抗争虽然失败了，但精神上的不屈更加坚定。"},{"id":"d5","text":"我知道等待我的是什么。但我无惧死亡，因为我已经为这个国家做了我能做的一切。","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"无惧死亡","historicalNote":"文天祥在被俘后始终表现出对死亡的坦然态度。他在狱中写的诗文充满了从容赴死的从容。","consequence":"你以坦然的态度面对即将到来的命运。你的从容让元军将领也为之动容。"},{"id":"d6","text":"我给家人写了一封信，告诉他们我的选择，希望他们能理解。","speaker":"我","avatar":"祥","score":80,"triggeredEvent":"遗书家人","historicalNote":"文天祥在狱中确实给家人写了书信，表达了对家人的牵挂和为国捐躯的决心。","consequence":"你给家人写了书信，字里行间既有对亲人的深深眷恋，也有为国殉难的坚定决心。家人读到后悲痛万分。"}],"nextActId":"act-5"},{"id":"act-5","title":"囚禁大都","isKeyAct":False,"sceneDescription":"你被押送到元大都，关押在兵马司狱中。忽必烈极为欣赏你的才华和气节，多次派人劝降，许以高官厚禄。但你的回答只有一个——绝不投降。阴暗的牢房中，你度过了三年的铁窗生涯，却在这期间写下了《正气歌》等不朽名篇。","npcDialogues":[{"speaker":"忽必烈","text":"文丞相，朕最敬佩有气节的人。只要你愿意归顺，朕封你为元朝丞相！","avatar":"忽"},{"speaker":"降臣","text":"天祥兄，大势已去，何必为了一个亡国的朝廷白白送命？归顺元朝吧！","avatar":"降"}],"dialogues":[{"id":"d1","text":"天地有正气，杂然赋流形。下则为河岳，上则为日星。我文天祥一身正气，岂能为高官厚禄折腰！","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"正气歌","historicalNote":"文天祥在狱中写下了《正气歌》，'天地有正气，杂然赋流形'成为千古名句，展现了他对正义和气节的坚守。","consequence":"你在狱中写下了《正气歌》，以天地正气自勉。这首诗成为中国文学史上最壮丽的爱国诗篇。"},{"id":"d2","text":"忽必烈陛下，我感谢您的好意。但我是大宋的臣子，忠臣不事二主，这是我的原则。","speaker":"我","avatar":"祥","score":90,"triggeredEvent":"拒绝劝降","historicalNote":"忽必烈确实多次派人劝降文天祥，许以高官厚禄，但文天祥始终不为所动。忽必烈虽然遗憾，但内心极为敬佩。","consequence":"你礼貌但坚定地拒绝了忽必烈的所有劝降。忽必烈虽然遗憾，但对你的气节佩服不已。"},{"id":"d3","text":"你让我归顺？你先看看我写的《正气歌》再说吧。","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"正气回应","historicalNote":"文天祥用《正气歌》回应所有的劝降者，诗中列举了历代忠臣义士的事迹，以明自己的心志。","consequence":"你的《正气歌》让所有劝降者哑口无言。诗中历数忠臣义士的事迹，表明了你效仿先贤的决心。"},{"id":"d4","text":"三年牢狱，我已将生死置之度外。你们用威胁、利诱、酷刑，都改变不了我的决心。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"坚贞不屈","historicalNote":"文天祥在狱中三年经受了各种考验，包括酷刑和利诱，但他始终没有屈服。","consequence":"你在三年的牢狱中始终坚贞不屈。各种威逼利诱都无法动摇你的信念。元军对你的敬佩与日俱增。"},{"id":"d5","text":"狱中虽然艰苦，但正好可以安静地思考和写作。我要用最后的时间留下一些有意义的东西。","speaker":"我","avatar":"祥","score":82,"triggeredEvent":"狱中写作","historicalNote":"文天祥在狱中除了《正气歌》，还写了大量诗文，记录了这段经历和他的思想。","consequence":"你在狱中坚持写作，将三年的牢狱生涯化为不朽的诗篇。这些作品后来结集传世。"},{"id":"d6","text":"那些降了元朝的宋朝旧臣来劝我，真是可笑。他们忘了自己的根在哪里。","speaker":"我","avatar":"祥","score":80,"triggeredEvent":"斥责降臣","historicalNote":"文天祥确实对那些投降元朝的南宋官员嗤之以鼻。他认为忠臣不事二主是做人的基本底线。","consequence":"你对那些劝降的降臣严词斥责，让他们羞愧不已。你的气节让投降者无地自容。"}],"nextActId":"act-6"},{"id":"act-6","title":"从容就义","isKeyAct":True,"sceneDescription":"至元十九年十二月初九，忽必烈最后亲自召见你，做了最后的劝降尝试。你仍然拒绝。忽必烈下令将你处死。你面朝南方——大宋故土的方向，从容赴死。在刑场上，你向围观的人群说了最后一句话，然后慷慨就义。年仅四十七岁。","npcDialogues":[{"speaker":"忽必烈","text":"文天祥，这是朕最后一次问你。你真的愿意为了一个亡国的朝代去死吗？","avatar":"忽"},{"speaker":"围观百姓","text":"那就是文丞相啊！他真是一位了不起的大英雄！","avatar":"民"}],"dialogues":[{"id":"d1","text":"吾事毕矣！大宋的丞相，只能站着死，不能跪着生！","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"从容就义","historicalNote":"文天祥临刑前向南而拜，从容就义。他的最后一句话'吾事毕矣'展现了一个爱国志士的终极圆满。他年仅四十七岁。","consequence":"你面朝南方从容就义，年仅四十七岁。围观百姓无不落泪。你的死震撼了天下，成为中华民族精神的永恒丰碑。"},{"id":"d2","text":"谢陛下赐死。我不求苟活，只求死得其所。","speaker":"我","avatar":"祥","score":90,"triggeredEvent":"谢恩赐死","historicalNote":"文天祥面对死刑时的从容态度让忽必烈也为之动容。忽必烈虽然下令处死他，但内心充满敬意。","consequence":"你以从容不迫的态度面对死亡，这种气概让在场所有人都为之动容。连忽必烈也不得不感叹。"},{"id":"d3","text":"我的妻子和孩子，对不起你们了。但为了这个国家，我别无选择。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"家国抉择","historicalNote":"文天祥在被俘后确实对家人深感愧疚。他牺牲了家庭幸福来成全家国大义。","consequence":"你对家人深感愧疚，但国难当头，你选择了大义。你的妻子后来也殉节而死，一家人都成为了忠义的典范。"},{"id":"d4","text":"忠臣不事二主，这是我从读书起就立下的志向。今天终于可以实现这个志向了。","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"忠臣不二","historicalNote":"文天祥'忠臣不事二主'的信念贯穿了他的一生，也成为后世最崇高的道德标杆。","consequence":"你用生命践行了自己'忠臣不事二主'的信念。这种精神跨越了时代，成为中华民族最珍贵的文化基因。"},{"id":"d5","text":"我的《正气歌》和《过零丁洋》就是我的遗言。后人读了就会明白，我为什么选择了这条道路。","speaker":"我","avatar":"祥","score":92,"triggeredEvent":"以诗为遗","historicalNote":"文天祥的诗文成为了他的精神遗嘱，激励了后世无数仁人志士。","consequence":"你的诗文成为了永恒的精神遗嘱。七百多年来，无数人在国家危难之时从你的诗文中汲取力量。"},{"id":"d6","text":"人生自古谁无死，留取丹心照汗青。今天，我终于可以践行自己的誓言了。","speaker":"我","avatar":"祥","score":93,"triggeredEvent":"丹心照汗青","historicalNote":"文天祥以生命践行了'留取丹心照汗青'的誓言。他的精神影响了后世无数爱国者，从岳飞到林则徐，从谭嗣同到孙中山，都能看到他的精神传承。","consequence":"你从容就义，用生命完成了最后的壮举。'人生自古谁无死，留取丹心照汗青'——你的名字与你的诗一起，永远镌刻在了中华民族的精神史册上。"}],"nextActId":"act-7"},{"id":"act-7","title":"忠魂不朽","isKeyAct":False,"sceneDescription":"你在柴市口英勇就义后，妻子欧阳氏收殓了你的遗体。你写下的《正气歌》和《过零丁洋》很快传遍天下，无数人为你落泪。忽必烈事后也感叹'好男子，不为我用，杀之诚可惜也'。后世将你列入忠义祠，与岳飞、陆秀夫并列。","npcDialogues":[{"speaker":"妻子欧阳氏","text":"夫君，你走了。你的气节，我会告诉我们的孩子，世世代代传下去。","avatar":"欧"},{"speaker":"后人","text":"文丞相的'人生自古谁无死，留取丹心照汗青'，每次读到都让人热泪盈眶。这就是中国人的脊梁啊！","avatar":"后"}],"dialogues":[{"id":"d1","text":"我的忠魂将与天地同在，与大宋同存。后人若读我的诗文，当知我为何而死。","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"忠魂永存","historicalNote":"文天祥被后世尊为'民族英雄'，他与岳飞并列为中国历史上最伟大的爱国将领。他的精神影响了中国七百多年。","consequence":"你的精神超越了生死，成为中华民族永恒的精神财富。七百多年来，每当国家面临危难，人们就会想起你的名字。"},{"id":"d2","text":"忠义二字，是我一生的信仰。不管时代如何变迁，这份信仰永远不会过时。","speaker":"我","avatar":"祥","score":92,"triggeredEvent":"信仰永恒","historicalNote":"文天祥的忠义精神在后世被不断传颂，成为中华民族核心价值观的重要组成部分。","consequence":"你的忠义信仰穿越时空，在每一个时代都能找到回响。你是中华精神的永恒象征。"},{"id":"d3","text":"忽必烈虽然杀了我，但他也不得不敬佩我的气节。这就是正义的力量。","speaker":"我","avatar":"祥","score":85,"triggeredEvent":"敌亦敬之","historicalNote":"忽必烈确实对文天祥的气节深感敬佩，他曾说'好男子，不为我用，杀之诚可惜也'。就连敌人也无法不尊重你的忠义。","consequence":"就连忽必烈也不得不承认，你的气节超越了政治立场。敌人对你的敬佩，是你忠义精神最有力量的证明。"},{"id":"d4","text":"我的妻子也殉节而死，我们一家都是忠义之魂。","speaker":"我","avatar":"祥","score":80,"triggeredEvent":"满门忠烈","historicalNote":"文天祥的妻子欧阳氏和子女在他死后也保持着忠节的品格，一家人都被后世传颂。","consequence":"你的家人继承了你的忠义精神，满门忠烈。这种精神在你们家族中代代相传。"},{"id":"d5","text":"后世在庐陵建了文丞相祠，人们在那里纪念我。这就是对忠义最好的传承。","speaker":"我","avatar":"祥","score":88,"triggeredEvent":"祠堂永祀","historicalNote":"后世在多地建立了文天祥纪念馆和祠堂，庐陵的文天祥纪念馆至今仍是重要的爱国主义教育基地。","consequence":"后人在各地建祠纪念你，你的故事代代相传。你成为了忠义精神的永恒象征。"},{"id":"d6","text":"人生自古谁无死，留取丹心照汗青。这句话，就是我为这个世界留下的最后礼物。","speaker":"我","avatar":"祥","score":95,"triggeredEvent":"丹心永恒","historicalNote":"文天祥以生命写就了中国历史上最壮丽的爱国诗篇。'人生自古谁无死，留取丹心照汗青'十四个字，成为中华民族精神的最高表达。","consequence":"你的名字与你的诗一起，永远镌刻在了中华民族的精神史上。七百多年过去了，你的丹心依然照耀着这片大地。文天祥，千古忠魂！"}],"nextActId":None}]}

liqingzhao = {"eraId":"song-yuan","eraName":"宋元","playerRole":"李清照","acts":[{"id":"act-1","title":"济南才女","isKeyAct":False,"sceneDescription":"济南府，李清照出生于书香门第，父亲李格非是著名学者，母亲王氏出身名门。少女时期的你才智过人，诗词书画样样精通。你的词作清新婉约，很快在济南文坛引起轰动。同龄女子还在学习女红，你却已经写出了让文坛前辈惊叹的作品。",
"npcDialogues":[{"speaker":"父亲李格非","text":"清照，你的词写得极好。但你是女子，在这个时代，才学未必能给你带来好的人生。","avatar":"格"},{"speaker":"赵明诚","text":"李小姐的词清新脱俗，读了令人心旷神怡。在下赵明诚，仰慕已久。","avatar":"赵"}],"dialogues":[{"id":"d1","text":"父亲，才学是我最大的财富。不管时代如何，我要用诗词记录我眼中的世界。","speaker":"我","avatar":"照","score":90,"triggeredEvent":"才女初露","historicalNote":"李清照少年时期的词作已展现出非凡的才华。她的《如梦令》等作品至今仍是中国文学的经典。","consequence":"你的词作在济南文坛引起轰动，被称为'天才少女'。你的才华让你的名字开始传遍文坛。"},{"id":"d2","text":"赵公子过奖了。在下虽然才疏学浅，但诗词之道，愿与公子切磋交流。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"结识赵明诚","historicalNote":"李清照与赵明诚志趣相投，二人以金石学问和诗词唱和为乐，成为文学史上最著名的伉俪之一。","consequence":"你与赵明诚一见如故，共同的志趣让你们迅速产生了深厚的感情。后来你们结为夫妻，成为文坛佳话。"},{"id":"d3","text":"我要多读书，多游历，开阔眼界。女子也应该有见识、有胸襟。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"博学多识","historicalNote":"李清照的博学在中国古代女作家中首屈一指，她精通经史、金石、诗词、书画，学识远超同时代大多数男性学者。","consequence":"你广泛涉猎各种学问，不仅精通诗词，还对金石学有深入研究。博学多才的你在文坛独树一帜。"},{"id":"d4","text":"我写的《如梦令》，朋友们都说好。但我总觉得还不够好，还要继续磨练。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"精益求精","historicalNote":"李清照的《如梦令·昨夜雨疏风骤》是她少女时期的代表作，'知否知否，应是绿肥红瘦'成为千古名句。","consequence":"你对文学创作精益求精的态度让你的作品越来越成熟。你的词风逐渐形成了清新婉约的独特风格。"},{"id":"d5","text":"母亲出身名门，教导我要做一个有见识的女子，不能只困在后院之中。","speaker":"我","avatar":"照","score":83,"triggeredEvent":"名门教养","historicalNote":"李清照的母亲王氏也出身名门，良好的家庭教育让李清照从小就拥有了开阔的视野和独立的性格。","consequence":"良好的家庭教养让你拥有了远超同龄女子的见识和胸襟。你从不认为女子就应该被困在后院中。"},{"id":"d6","text":"我对金石古物也很感兴趣。如果能收集研究，一定很有趣。","speaker":"我","avatar":"照","score":80,"triggeredEvent":"金石兴趣","historicalNote":"李清照对金石学的兴趣后来成为她和赵明诚共同的学术追求。两人合著的《金石录》是中国金石学的重要著作。","consequence":"你对金石古物的兴趣在日后成为你和赵明诚共同的事业。这种学术追求在当时极为罕见，尤其对一位女性来说。"}],"nextActId":"act-2"},{"id":"act-2","title":"新婚燕尔","isKeyAct":False,"sceneDescription":"你与赵明诚新婚燕尔，夫妻二人志趣相投，生活美满。赵明诚在太学攻读，每月回家后与你一起品茶论学、赏玩金石书画。你们最大的乐趣就是去大相国寺的集市淘宝，搜寻古碑拓片和珍贵书籍。虽然经济并不宽裕，但精神生活无比丰富。",
"npcDialogues":[{"speaker":"赵明诚","text":"清照，你看这块碑拓，上面的字多漂亮！可惜我们手头不宽裕，买不起太多。","avatar":"赵"},{"speaker":"古董商","text":"赵公子、赵夫人，你们每次来都要看半天，又买不起。下次带了钱再来吧！","avatar":"商"}],"dialogues":[{"id":"d1","text":"明诚，我们虽然买不起太多古物，但可以将它们拓印下来，回去仔细研究。这也很有意义。","speaker":"我","avatar":"照","score":90,"triggeredEvent":"拓印研究","historicalNote":"李清照和赵明诚经济不宽裕时确实经常拓印金石碑刻进行研究，这种学术热情后来促成了《金石录》的诞生。","consequence":"你们虽然买不起太多古物，但通过拓印和研究积累了大量金石学资料。这段艰苦但充实的生活成为你们最珍贵的回忆。"},{"id":"d2","text":"明诚，我们把每月的俸禄省下来，一半用来买书和古物，一半用于日常开销。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"节衣缩食","historicalNote":"李清照和赵明诚确实节衣缩食来收集金石书画，他们的收藏后来成为《金石录》的重要基础。","consequence":"你们节衣缩食，将省下的钱用于购买书籍和古物。日积月累，你们的收藏越来越丰富。"},{"id":"d3","text":"我们一起品茶论词，玩猜书游戏。我说一个典故，你猜在哪本书的哪一页，怎么样？","speaker":"我","avatar":"照","score":88,"triggeredEvent":"赌书消得泼茶香","historicalNote":"李清照与赵明诚'赌书泼茶'的故事是文学史上最动人的夫妻趣事之一，被后人传为佳话。","consequence":"你们玩起了赌书游戏，乐在其中。李清照后来回忆这段时光时写下'赌书消得泼茶香'的名句，成为千古佳话。"},{"id":"d4","text":"明诚，你的词写得好，但我觉得在意境上还可以再提高。让我帮你改改。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"诗词交流","historicalNote":"李清照的词学造诣实际上高于赵明诚，她曾直言不讳地指出丈夫词作的不足，这在当时极为大胆。","consequence":"你坦诚地帮助赵明诚提高词作水平，夫妻间的诗词交流让你们的感情更加深厚。"},{"id":"d5","text":"我们计划编纂一部金石学著作，将这些年的收藏和研究整理成书。","speaker":"我","avatar":"照","score":87,"triggeredEvent":"计划金石录","historicalNote":"李清照和赵明诚共同计划编纂《金石录》，这部书后来成为中国金石学的经典著作。","consequence":"你们开始规划《金石录》的编纂工作。这本书将成为你们毕生心血的结晶，也是中国学术史上的重要著作。"},{"id":"d6","text":"明诚，今天下雨，我们可以在家读书，何不把这首新词填完？","speaker":"我","avatar":"照","score":80,"triggeredEvent":"雨日作词","historicalNote":"李清照的《如梦令》等词作多是在这样平静而温馨的日常生活中创作的。这些作品展现了她婉约词风的极致。","consequence":"你们在雨天的家中读书作词，享受着平静而温馨的生活。你的词作在这种氛围中愈发精妙。"}],"nextActId":"act-3"},{"id":"act-3","title":"收集金石","isKeyAct":False,"sceneDescription":"赵明诚出仕后，你们的生活条件有所改善。你们投入大量精力和财力收集金石书画，建立了可观的收藏。每当获得珍贵的古物，你们都会彻夜研究考证，兴奋不已。然而靖康之变即将到来，你们辛苦收集的宝藏即将面临灭顶之灾。",
"npcDialogues":[{"speaker":"赵明诚","text":"清照，你看这卷古画，保存得极好！我们已经收集了整整十五车的金石书画了！","avatar":"赵"},{"speaker":"李清照","text":"是啊，这些年来我们的心血都在这里。明诚，你一定要把《金石录》写完。","avatar":"照"}],"dialogues":[{"id":"d1","text":"这些金石书画是我们的生命。每获得一件珍品，我都觉得拥有了整个世界。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"珍视收藏","historicalNote":"李清照和赵明诚的金石收藏多达两千余件，包括大量珍贵书籍、书画和金石碑刻。这些收藏是他们二十多年心血的结晶。","consequence":"你精心管理着日益丰富的收藏，每件珍品你都如数家珍。这些金石书画不仅是学术资料，更是你们的情感寄托。"},{"id":"d2","text":"我在整理这些收藏的过程中，也在撰写《金石录》的初稿。希望有一天能成书。","speaker":"我","avatar":"照","score":90,"triggeredEvent":"撰写金石录","historicalNote":"《金石录》是李清照和赵明诚共同编撰的金石学著作，记录了两千余件金石碑刻的考证研究。这是中国金石学的奠基之作。","consequence":"你积极撰写《金石录》的初稿，将每一件收藏的来历、特征和考证结果详细记录。这项工作持续了多年。"},{"id":"d3","text":"朝廷局势不稳，金兵威胁日益严重。我们要不要先把收藏转移到安全的地方？","speaker":"我","avatar":"照","score":85,"triggeredEvent":"担忧时局","historicalNote":"李清照确实对时局有清醒的认识，靖康之变前夕她曾建议赵明诚转移收藏，但当时局势变化太快。","consequence":"你敏锐地感觉到时局的危急，但局势恶化得太快，你们来不及完全转移收藏。靖康之变即将改变一切。"},{"id":"d4","text":"明诚，你在外做官要小心。朝廷中奸臣当道，局势复杂。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"提醒丈夫","historicalNote":"赵明诚在地方任职期间，李清照独自在家管理收藏，同时密切关注时局。","consequence":"你独自在家管理庞大的收藏，同时关心丈夫的仕途安全。你的坚强和智慧让人敬佩。"},{"id":"d5","text":"我趁明诚不在的时候，继续整理金石录的考证笔记。这项工作不能停。","speaker":"我","avatar":"照","score":83,"triggeredEvent":"独自整理","historicalNote":"李清照在赵明诚外出任职时独自承担了金石收藏的管理和研究工作。她的学术能力完全可以独立完成这项工作。","consequence":"你独自继续整理金石录的考证笔记，展现了极强的学术独立性和组织能力。你的贡献不亚于赵明诚。"},{"id":"d6","text":"我们的收藏越来越丰富，将来可以建一个私人藏书楼来妥善保管。","speaker":"我","avatar":"照","score":80,"triggeredEvent":"藏书计划","historicalNote":"李清照和赵明诚的收藏规模在当时首屈一指，他们确实考虑过建立专门的藏书楼。但靖康之变让这个计划落空了。","consequence":"你们计划中的藏书楼还没来得及建成，时代的巨变就摧毁了一切。但你的学术记录保留了下来。"}],"nextActId":"act-4"},{"id":"act-4","title":"靖康之变","isKeyAct":True,"sceneDescription":"靖康二年，金兵攻破汴京，北宋灭亡。你和赵明诚被迫南下逃难，多年收集的金石书画大部分在战火中散失。十五车的珍贵收藏，最终只抢救出了少量。你站在满地狼藉的废墟中，看着毕生心血化为乌有，悲痛欲绝。但更大的苦难还在后面。",
"npcDialogues":[{"speaker":"赵明诚","text":"清照，我们的收藏大部分都丢了……二十年的心血啊！我对不起你，也对不起这些珍贵的文物。","avatar":"赵"},{"speaker":"逃难百姓","text":"金兵来了！快跑啊！什么金银财宝都不要了，保命要紧！","avatar":"民"}],"dialogues":[{"id":"d1","text":"二十年的心血付之东流，我的心在滴血。但人活着，就还有希望。明诚，我们活下去！","speaker":"我","avatar":"照","score":90,"triggeredEvent":"劫后余生","historicalNote":"靖康之变中李清照和赵明诚损失了大部分金石收藏，这是中国文化遗产的重大损失。李清照后来在《金石录后序》中详细记录了这段经历。","consequence":"你在废墟中含泪南逃，虽然失去了大部分收藏，但带着仅存的部分文稿和少量珍品。活下去成了你唯一的信念。"},{"id":"d2","text":"明诚，你在淄州任上弃城逃跑，这让我非常失望。作为朝廷命官，你怎么能丢下百姓先逃？","speaker":"我","avatar":"照","score":85,"triggeredEvent":"失望丈夫","historicalNote":"赵明诚在淄州确实曾弃城逃跑，李清照对此深感失望。她在乌江亭写的诗暗含了对丈夫的批评。","consequence":"你对赵明诚的怯懦行为深感失望，夫妻关系出现了裂痕。但赵明诚也深感愧疚，两人的关系后来有所修复。"},{"id":"d3","text":"逃难路上，我尽量多带一些书籍和金石拓片。这些东西比金银财宝更珍贵。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"抢救文物","historicalNote":"李清照在逃难中确实尽力抢救了部分金石书画和书籍，虽然数量有限，但这些保存下来的文献极为珍贵。","consequence":"你在逃难中尽力抢救了大量书籍和拓片，虽然只是一小部分，但这些保存下来的文献后来成为《金石录》的重要依据。"},{"id":"d4","text":"我们在逃难途中，看到无数百姓流离失所。个人的损失再大，也比不上国家的灾难。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"国难当头","historicalNote":"靖康之变给整个中原地区带来了毁灭性的灾难。李清照在个人的悲痛之外，也对国家的命运深感忧虑。","consequence":"你从个人的悲痛中走出来，将目光投向了更广阔的国家苦难。你的词风也因此变得更加深沉。"},{"id":"d5","text":"明诚病倒了，我要全力照顾他。不管发生什么，我们都要一起面对。","speaker":"我","avatar":"照","score":80,"triggeredEvent":"照顾丈夫","historicalNote":"赵明诚在南逃途中确实身体越来越差，最终在建康病逝。李清照在他最后的时光里一直陪伴在他身边。","consequence":"你悉心照顾生病的赵明诚，在逃难的艰难环境中尽了最大的努力。赵明诚对你的付出深感愧疚和感激。"},{"id":"d6","text":"我将这段逃难的经历记录下来，将来作为《金石录》后序的一部分。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"记录经历","historicalNote":"李清照后来写成的《金石录后序》是中国散文史上的名篇，详细记录了她与赵明诚收集金石的经历和靖康之变后的遭遇。","consequence":"你将逃难的经历详细记录，这些文字后来成为《金石录后序》的重要组成部分。这篇后序成为中国文学史上最动人的散文之一。"}],"nextActId":"act-5"},{"id":"act-5","title":"丧夫之痛","isKeyAct":True,"sceneDescription":"建康城中，赵明诚在病中撒手人寰。你失去了相伴二十多年的丈夫，悲痛欲绝。更糟糕的是，赵明诚去世后，你孤立无援，周围的人开始觊觎你们残存的金石收藏。一个孤身女子在乱世中艰难求存，命运对你如此残酷。",
"npcDialogues":[{"speaker":"赵明诚","text":"清照……对不起……金石录……一定要……写完……","avatar":"赵"},{"speaker":"李清照","text":"明诚！你不能丢下我一个人！我们还有很多事没做完啊！","avatar":"照"}],"dialogues":[{"id":"d1","text":"明诚走了，我心中的依靠没了。但我答应过他，一定要把《金石录》写完。我一定要活下去！","speaker":"我","avatar":"照","score":92,"triggeredEvent":"坚守承诺","historicalNote":"赵明诚去世后，李清照在极其艰难的条件下完成了《金石录》的编纂工作，实现了对丈夫的承诺。","consequence":"你在丈夫去世后化悲痛为力量，决心完成《金石录》。这份承诺支撑你度过了最黑暗的时光。"},{"id":"d2","text":"物是人非事事休，欲语泪先流。明诚，你在那边还好吗？","speaker":"我","avatar":"照","score":93,"triggeredEvent":"物是人非","historicalNote":"李清照在赵明诚去世后写下了大量怀念丈夫的词作，'物是人非事事休，欲语泪先流'成为千古绝唱。","consequence":"你将对丈夫的思念化为不朽的词篇。'物是人非事事休'成为你内心最真实的写照。这些词作在文学史上占有独特的地位。"},{"id":"d3","text":"有人觊觎我们的收藏，我必须想办法保护好这些珍贵的文物。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"保护文物","historicalNote":"赵明诚去世后，李清照确实面临收藏被觊觎的问题。她尽了最大努力保护这些珍贵的文物。","consequence":"你在孤身无援的情况下想尽办法保护残存的收藏。虽然最终又损失了一部分，但你尽力了。"},{"id":"d4","text":"乱世之中，我一个女子实在难以自保。我需要找到一个可以依靠的人。","speaker":"我","avatar":"照","score":75,"triggeredEvent":"艰难处境","historicalNote":"赵明诚去世后，李清照的处境确实非常艰难。她后来再婚张汝舟，但发现张汝舟只是为了骗取她的收藏。","consequence":"你在乱世中苦苦挣扎，尝试寻找一个可以依靠的人。但这并不容易。"},{"id":"d5","text":"我要带着《金石录》的文稿南下，找一处安身之所。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"携稿南下","historicalNote":"李清照在赵明诚去世后带着《金石录》的文稿南渡，经历了极为艰难的旅程。","consequence":"你带着《金石录》的文稿辗转南下，在途中经历了重重困难。但你始终将这份文稿视为生命中最珍贵的东西。"},{"id":"d6","text":"我先去投奔明诚的亲友，在那里安顿下来，再慢慢整理《金石录》。","speaker":"我","avatar":"照","score":78,"triggeredEvent":"投奔亲友","historicalNote":"李清照在赵明诚去世后确实投奔了亲友，但乱世中人际关系的脆弱让她深感世态炎凉。","consequence":"你投奔了赵明诚的亲友，但乱世中人们自顾不暇，你得到的帮助有限。你深感世态炎凉。"}],"nextActId":"act-6"},{"id":"act-6","title":"乱世飘零","isKeyAct":False,"sceneDescription":"你在乱世中辗转漂泊，先后到过越州、明州、台州、温州、金华等地。所带的书册金石在途中又散失了不少。为了自保，你一度再婚，却发现第二任丈夫张汝舟只是为了你的收藏而来。你毅然告官离婚，在当时的社会环境下承受了巨大的舆论压力。",
"npcDialogues":[{"speaker":"张汝舟","text":"你那些金石书画，给我看看嘛。我们都是夫妻了，你的东西不就是我的吗？","avatar":"张"},{"speaker":"亲友","text":"清照，你怎么能告官离婚？一个女人告夫，这可是大逆不道啊！","avatar":"亲"}],"dialogues":[{"id":"d1","text":"张汝舟这个人根本不是为了爱我，他只是为了骗取我的收藏。我不能和一个骗子过一辈子！","speaker":"我","avatar":"照","score":90,"triggeredEvent":"毅然离婚","historicalNote":"李清照发现张汝舟只是为了骗取收藏后，毅然告官离婚。在当时的社会环境下，一个女人告夫离婚需要极大的勇气。按宋律，妻子告夫要坐牢两年。","consequence":"你不顾社会压力和可能面临的牢狱之灾，毅然告官离婚。你的勇气让后世无数人敬佩。虽然因此被关押了九天，但你赢得了自由和尊严。"},{"id":"d2","text":"按大宋律法，妻子告夫要坐牢两年。但我宁愿坐牢，也不愿与一个骗子共度余生！","speaker":"我","avatar":"照","score":92,"triggeredEvent":"宁坐牢","historicalNote":"李清照告夫离婚后被关押了九天，在亲友的营救下获释。按宋律她应坐牢两年，但实际只关了九天。","consequence":"你被关押了九天，在亲友营救下获释。虽然失去了自由一段时间，但你赢得了自尊。这段经历让你更加坚强。"},{"id":"d3","text":"逃难途中又损失了不少收藏，但最重要的《金石录》文稿我一定要保护好。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"保护文稿","historicalNote":"李清照在逃难途中确实又损失了部分收藏，但她始终将《金石录》的文稿视为最重要的东西，拼尽全力保护。","consequence":"你在漂泊途中拼尽全力保护《金石录》文稿，虽然又损失了部分收藏，但最重要的文稿保存了下来。"},{"id":"d4","text":"世人对我的再婚和离婚指指点点，我不管。我的人生，不需要别人评判。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"不畏人言","historicalNote":"李清照的再婚和离婚在当时引起了巨大的社会争议，但她始终不畏人言，坚持做真实的自己。","consequence":"你对外界的指指点点不屑一顾。你的人生不需要别人来评判。这种独立和勇气在古代女性中极为罕见。"},{"id":"d5","text":"我四处漂泊，居无定所。但只要有笔墨在手，我就能写词。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"漂泊中写作","historicalNote":"李清照在漂泊期间仍然坚持写作，她的后期词作风格变得更加深沉苍凉。","consequence":"你在漂泊中坚持写作，词风从早年的清新婉约变得更加深沉苍凉。生活的苦难让你的创作达到了更高的境界。"},{"id":"d6","text":"明诚，你在天之灵保佑我吧。我一定会完成《金石录》，不辜负你的期望。","speaker":"我","avatar":"照","score":83,"triggeredEvent":"丈夫之灵","historicalNote":"李清照在晚年常常怀念赵明诚，对丈夫的深情贯穿了她后期的全部作品。","consequence":"你在孤独的夜晚常常向已逝的丈夫倾诉。这份深沉的感情融入了你的词作中，打动了无数后世读者的心。"}],"nextActId":"act-7"},{"id":"act-7","title":"晚年凄凉","isKeyAct":False,"sceneDescription":"南宋朝廷偏安江南，你的晚年生活凄凉孤独。你先后到过临安、金华等地，最终在临安定居。晚年的你仍然笔耕不辍，完成了《金石录》的编纂，并创作了大量怀念故国和丈夫的词作。'寻寻觅觅，冷冷清清，凄凄惨惨戚戚'——这首词浓缩了你晚年的全部心境。",
"npcDialogues":[{"speaker":"邻居老妇","text":"李夫人，一个人住太辛苦了。要不要搬过来和我们一起住？","avatar":"邻"},{"speaker":"李清照","text":"寻寻觅觅，冷冷清清，凄凄惨惨戚戚。这次第，怎一个愁字了得！","avatar":"照"}],"dialogues":[{"id":"d1","text":"寻寻觅觅，冷冷清清，凄凄惨惨戚戚。这一生，从济南才女到流亡老妇，我的心中有多少愁！","speaker":"我","avatar":"照","score":95,"triggeredEvent":"声声慢","historicalNote":"李清照晚年创作的《声声慢·寻寻觅觅》被誉为中国词史上最凄美的词作之一。叠词的运用达到了登峰造极的境界。","consequence":"你写下了这首《声声慢》，叠词的运用出神入化，将晚年的凄凉孤寂表达得淋漓尽致。这首词成为中国文学史上最动人的作品之一。"},{"id":"d2","text":"我终于完成了《金石录》的编纂和校对。明诚，你的遗愿，我终于实现了！","speaker":"我","avatar":"照","score":92,"triggeredEvent":"完成金石录","historicalNote":"李清照在极其艰难的条件下完成了《金石录》的编纂工作。她在《金石录后序》中详细记录了与赵明诚收集金石的经历。","consequence":"你含泪完成了《金石录》的编纂，实现了对赵明诚的承诺。这部著作成为中国金石学的经典，你与赵明诚的名字永远联在了一起。"},{"id":"d3","text":"我老了，孤身一人。但只要还能写词，我就还有活下去的理由。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"以词为伴","historicalNote":"李清照晚年虽然孤苦无依，但始终没有放弃文学创作。她的后期词作深沉而有力，展现了一个女性在苦难中的坚强。","consequence":"你以词为伴，在孤独中坚持创作。你的词作不仅记录了个人的悲欢，也见证了一个时代的兴亡。"},{"id":"d4","text":"国家破碎，丈夫离世，收藏散失。我这一生经历了太多的苦难。","speaker":"我","avatar":"照","score":82,"triggeredEvent":"苦难一生","historicalNote":"李清照的一生经历了靖康之变、丧夫、流亡、再婚离婚等一系列苦难。这些经历深刻地影响了她的后期创作。","consequence":"你回顾一生的苦难，虽然悲苦，但你的坚强和才华让你在逆境中依然绽放光芒。"},{"id":"d5","text":"我把毕生的词作整理出来，编成集子，希望能传之后世。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"整理词集","historicalNote":"李清照的词集《漱玉词》是中国文学史上的经典，她的词被称为'易安体'，对后世词的发展产生了深远影响。","consequence":"你将毕生的词作整理成集，后世称为《漱玉词》。你的词风独特，被称为'易安体'，影响了后世无数词人。"},{"id":"d6","text":"我虽然是女子，但我的词不比任何一个男人写得差。婉约之中有豪气，这才是我李清照的风格。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"婉约豪气","historicalNote":"李清照不仅有婉约的词风，也有'生当作人杰，死亦为鬼雄'这样的豪放之作。她的创作风格超越了性别局限。","consequence":"你的词作风格超越了传统的性别框架，婉约中有豪气，细腻中有力量。你是中国文学史上最伟大的女词人。"}],"nextActId":"act-8"},{"id":"act-8","title":"词坛永恒","isKeyAct":False,"sceneDescription":"你在一个秋日的黄昏安静地离开了这个世界。从济南的才女到金石学的大家，从幸福的妻子到孤独的老人，你用一生诠释了什么是中国女性的力量和才华。你的词作跨越千年，至今仍被人们深情吟诵。婉约派的开山之人，千古第一才女——李清照。",
"npcDialogues":[{"speaker":"李清照","text":"生当作人杰，死亦为鬼雄。我李清照的一生，虽然坎坷，但从不曾辜负自己的才华和信念。","avatar":"照"},{"speaker":"后人","text":"李清照不仅是'千古第一才女'，她的词更是中国文学史上的一颗明珠。她的一生告诉世界，女子的才华不输任何男人。","avatar":"后"}],"dialogues":[{"id":"d1","text":"我这一生，有欢笑也有泪水，有幸福也有苦难。但最重要的是，我从未放弃过自己。","speaker":"我","avatar":"照","score":95,"triggeredEvent":"千古才女","historicalNote":"李清照被后世尊为'千古第一才女'和'婉约派之祖'。她的词作《漱玉词》成为中国文学史上的经典。","consequence":"你带着对人生的完整感悟离去。后世称你为'千古第一才女'，你的词作至今仍在人们心中激荡。"},{"id":"d2","text":"我的《金石录》和《漱玉词》，就是我留给这个世界的礼物。","speaker":"我","avatar":"照","score":92,"triggeredEvent":"双重遗产","historicalNote":"李清照在金石学和词学两个领域都做出了巨大贡献。《金石录》和《漱玉词》是她在学术和文学两个领域的巅峰之作。","consequence":"你的《金石录》和《漱玉词》成为中国学术史和文学史的双重经典。你的才华横跨了两个领域，这在古代女性中绝无仅有。"},{"id":"d3","text":"生当作人杰，死亦为鬼雄。即使在最困难的时期，我也从来没有放弃过信念。","speaker":"我","avatar":"照","score":90,"triggeredEvent":"人杰鬼雄","historicalNote":"李清照的'生当作人杰，死亦为鬼雄'展现了她骨子里的豪迈气概。这首诗打破了人们对她只有婉约风格的刻板印象。","consequence":"你的豪迈气概让后世对你有了更全面的认识。你不只是婉约的词人，更是一个有骨气、有担当的大写的人。"},{"id":"d4","text":"明诚，我们终于又在另一个世界团聚了。这些年的苦难，都过去了。","speaker":"我","avatar":"照","score":85,"triggeredEvent":"夫妻团聚","historicalNote":"李清照与赵明诚的爱情故事是中国文学史上最动人的篇章之一，'赌书消得泼茶香'成为千古佳话。","consequence":"你的灵魂终于与赵明诚在另一个世界团聚。你们的爱情故事跨越了生死，成为后世最动人的佳话。"},{"id":"d5","text":"后世的女孩子们，你们要相信自己的才华。不要让任何人告诉你，女子不能做什么。","speaker":"我","avatar":"照","score":88,"triggeredEvent":"激励后世","historicalNote":"李清照的独立人格和不屈精神成为后世女性的精神榜样。她的故事激励了无数女性追求自己的梦想。","consequence":"你的一生成为后世女性的精神灯塔。你的故事告诉每一个女性：才华不分性别，独立和勇气才是最珍贵的品质。"},{"id":"d6","text":"寻寻觅觅，冷冷清清，凄凄惨惨戚戚。这是我最后的心境，也是我对这个世界最后的礼物。","speaker":"我","avatar":"照","score":93,"triggeredEvent":"易安永恒","historicalNote":"李清照是中国文学史上最伟大的女词人，也是中国文化史上最具影响力的女性之一。她的一生和作品是中华文明中最珍贵的文化遗产之一。","consequence":"你安静地离去。千年之后，'寻寻觅觅'的旋律仍然在中华大地上回荡。易安居士，千古第一才女，你的名字永远不会被遗忘。"}],"nextActId":None}]}

zhengchenggong = {"eraId":"ming-qing","eraName":"明清","playerRole":"郑成功","acts":[{"id":"act-1","title":"少年磨砺","isKeyAct":False,"sceneDescription":"福建南安，少年郑成功出生于中日混血家庭，父亲郑芝龙是东南亚最大的海上贸易商和海盗头目，母亲田川氏是日本武士之女。你少年时在日本平户长大，七岁才回到中国。东西方文化的碰撞塑造了你独特的性格——既有武士的果敢，又有儒生的智慧。",
"npcDialogues":[{"speaker":"郑芝龙","text":"森儿，你是我的长子，将来要继承我的事业。大明正值多事之秋，你要好好读书习武。","avatar":"芝"},{"speaker":"母亲田川氏","text":"森儿，你身上流着武士的血，要做一个有勇气、有担当的人。","avatar":"田"}],"dialogues":[{"id":"d1","text":"父亲，我要读书习武，将来为国效力。大明正在经历风雨，我要成为保卫国家的人。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"立志报国","historicalNote":"郑成功少年时便展现出非凡的志向，他后来果然成为反清复明的重要领袖，被南明永历帝赐姓'朱'，称'国姓爷'。","consequence":"你发奋读书习武，立志报国。你的才能和志向逐渐展露，引起了南明朝廷的注意。"},{"id":"d2","text":"我在日本长大，学到了很多中国没有的东西。这些见识将来一定有用。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"东西交融","historicalNote":"郑成功在日本长大的经历让他具有国际视野，这在他后来的海上贸易和军事活动中发挥了重要作用。","consequence":"你独特的跨文化经历让你具有开阔的视野。这种优势在日后让你在海上活动中如鱼得水。"},{"id":"d3","text":"母亲教我的武士精神——忠义、勇气、荣誉，我一辈子都不会忘记。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"武士精神","historicalNote":"郑成功的母亲田川氏对他的影响深远。后来母亲在战乱中遇难的传说更加坚定了他抗清的决心。","consequence":"武士精神成为你一生的信条。忠义和勇气在你的性格中深深扎根。"},{"id":"d4","text":"父亲的海上势力庞大，但我要走正道，用这些力量报效国家。","speaker":"我","avatar":"成","score":80,"triggeredEvent":"正道报国","historicalNote":"郑成功继承了父亲的海上力量，但将其用于抗清复明的事业，而非单纯的商业或海盗活动。","consequence":"你立志将父亲的海上力量用于报效国家的事业。这种转变展现了你的政治远见。"},{"id":"d5","text":"我要进南京国子监读书，接受最好的儒学教育。","speaker":"我","avatar":"成","score":83,"triggeredEvent":"南京求学","historicalNote":"郑成功确实在南京国子监求学，接受了系统的儒家教育。他的儒家忠君思想是后来坚持抗清的精神基础。","consequence":"你在南京国子监深入学习了儒家经典，忠君爱国的思想深深烙印在你的心中。"},{"id":"d6","text":"天下大乱，我要结交志同道合的豪杰，为将来做准备。","speaker":"我","avatar":"成","score":78,"triggeredEvent":"结交豪杰","historicalNote":"郑成功在青年时期确实结交了大量志同道合的豪杰，这些人后来成为他抗清复明的重要部将。","consequence":"你广交天下豪杰，建立了一批忠心耿耿的追随者。这些人才是日后事业的基石。"}],"nextActId":"act-2"},{"id":"act-2","title":"举旗抗清","isKeyAct":True,"sceneDescription":"清军南下，弘光政权覆灭，你的父亲郑芝龙选择投降清朝。你坚决反对，但无力阻止。清军进入福建后，你的母亲在战乱中不幸遇难。悲愤交加的你，在金门誓师抗清，举起了'反清复明'的大旗。这一年，你二十二岁。",
"npcDialogues":[{"speaker":"郑芝龙","text":"森儿，大势已去，投降清朝是唯一的选择。你不要做无谓的牺牲。","avatar":"芝"},{"speaker":"部将","text":"大公子，我们愿意跟随您！您的母亲在天之灵一定会保佑您的！","avatar":"将"}],"dialogues":[{"id":"d1","text":"父亲降清，是父亲的耻辱！我郑成功决不投降！母亲被清军所害，此仇不报，誓不为人！","speaker":"我","avatar":"成","score":95,"triggeredEvent":"金门誓师","historicalNote":"郑成功在金门誓师抗清，从此开始了长达十余年的反清复明斗争。永历帝封他为'延平郡王'，赐姓'朱'，故称'国姓爷'。","consequence":"你在金门誓师，举起了反清复明的大旗。永历帝封你为延平郡王。你从此以'国姓爷'之名威震天下。"},{"id":"d2","text":"父亲虽然降清，但那是他自己的选择。我要走我自己的路。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"父子决裂","historicalNote":"郑成功与父亲郑芝龙因为降清问题彻底决裂。郑芝龙后来被清朝软禁至死。","consequence":"你与父亲彻底决裂，走上了独立抗清的道路。虽然内心痛苦，但信念不可动摇。"},{"id":"d3","text":"我要先建立一支强大的水师，控制沿海海域，为抗清提供军事和经济基础。","speaker":"我","avatar":"成","score":90,"triggeredEvent":"建立水师","historicalNote":"郑成功建立了一支强大的水师，以厦门、金门为根据地，控制了东南沿海的海上贸易和军事力量。","consequence":"你着手建立水师，以厦门、金门为根据地。你的水师很快成为东南沿海最强大的海上力量。"},{"id":"d4","text":"我要招募义军，凡是愿意反清复明的英雄豪杰，都可以加入我的队伍。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"招募义军","historicalNote":"郑成功广泛招募反清义士，他的队伍中既有明军旧部，也有各地来投的义军和海盗。","consequence":"你广泛招募义军，队伍迅速壮大。各种背景的人汇聚在你的旗帜下，共同为反清复明而战。"},{"id":"d5","text":"母亲在天之灵看着我，我不能让她失望。我一定要为母亲报仇！","speaker":"我","avatar":"成","score":82,"triggeredEvent":"为母报仇","historicalNote":"郑成功的母亲在清军入侵中遇难的传说极大地激发了他的抗清决心。母亲的死成为他一生中最深的痛。","consequence":"母亲遇难的消息让你悲愤万分，你将这份悲痛化为战斗的动力。为母报仇成为了你坚持抗清的精神支柱。"},{"id":"d6","text":"清军虽然强大，但他们不熟悉海战。我要利用海上优势与他们周旋。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"海上战略","historicalNote":"郑成功确实利用海上优势与清军周旋，他的水师在沿海多次击败清军，成为清军的心腹大患。","consequence":"你充分发挥海上优势，多次在沿海击败清军。你的水师让清军头疼不已，无法在东南沿海站稳脚跟。"}],"nextActId":"act-3"},{"id":"act-3","title":"围攻南京","isKeyAct":False,"sceneDescription":"永历十三年，你率领水师沿长江北上，一度攻入长江口，兵锋直指南京。这是抗清复明事业最接近成功的一次。然而在南京城下，你因为战略失误未能攻克城池，最终不得不退回沿海。这次失败让你深刻反思，也让你开始考虑新的战略方向。",
"npcDialogues":[{"speaker":"部将","text":"国姓爷，我们已经打到南京城下了！只要再加把劲，就能收复南京！","avatar":"将"},{"speaker":"清军将领","text":"郑成功虽然兵临城下，但他犯了一个致命的错误——没有立即攻城。这给了我们喘息的时间。","avatar":"清"}],"dialogues":[{"id":"d1","text":"南京就在眼前，我们必须趁清军还没有反应过来的时候立即攻城！","speaker":"我","avatar":"成","score":88,"triggeredEvent":"攻城之误","historicalNote":"郑成功确实在南京城下犯了犹豫不决的错误，没有趁清军措手不及时攻城，最终错失了最佳时机。这是他抗清生涯中最大的遗憾。","consequence":"你在关键时刻犹豫了太久，给了清军喘息的时间。清军援兵赶到后，你被迫撤退。这次失败让你痛定思痛。"},{"id":"d2","text":"虽然南京之战失败了，但我们已经证明了清军并非不可战胜。士气没有垮！","speaker":"我","avatar":"成","score":82,"triggeredEvent":"鼓舞士气","historicalNote":"郑成功北伐虽然失败，但长江之战的壮举极大地鼓舞了抗清势力的士气，证明了清军并非不可战胜。","consequence":"你在退兵途中鼓舞士气，让将士们明白失败只是暂时的。北伐虽然没有成功，但极大地振奋了人心。"},{"id":"d3","text":"沿海根据地需要巩固，我不能总是外出远征，后方空虚会被敌人利用。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"巩固后方","historicalNote":"郑成功在北伐失败后确实认识到巩固后方的重要性，开始更加注重经营厦门、金门等根据地。","consequence":"你开始注重巩固沿海根据地，发展经济和军事实力。后方稳固了，才能支撑长期的抗清斗争。"},{"id":"d4","text":"南京之战的失败让我明白，光靠水师不足以推翻清朝。我需要一个稳固的根据地来建立政权。","speaker":"我","avatar":"成","score":90,"triggeredEvent":"反思战略","historicalNote":"南京之战的失败促使郑成功开始考虑建立稳固的根据地。他最终选择了台湾作为新的战略方向。","consequence":"你深刻反思了战略失误，认识到建立稳固根据地的重要性。这个认识促使你将目光投向了台湾。"},{"id":"d5","text":"我听说荷兰人占据了台湾，在那里欺压中国百姓。也许台湾就是我们要找的地方。","speaker":"我","avatar":"成","score":92,"triggeredEvent":"目标台湾","historicalNote":"郑成功在南京之战失败后开始考虑收复台湾。台湾的战略价值极高，可以作为稳固的抗清根据地。","consequence":"你将目光投向了台湾。这座美丽的岛屿将成为你事业的转折点，也将成为中国历史上的重要篇章。"},{"id":"d6","text":"我要招揽通晓台湾情况的人才，详细了解那里的地形和荷兰人的布防。","speaker":"我","avatar":"成","score":83,"triggeredEvent":"情报收集","historicalNote":"郑成功确实详细收集了台湾的情报，包括地形、荷兰人的兵力部署和当地居民的情况。","consequence":"你招揽了熟悉台湾的通译和商人，全面了解了台湾的情况。这些情报为你日后收复台湾打下了基础。"}],"nextActId":"act-4"},{"id":"act-4","title":"渡海东征","isKeyAct":True,"sceneDescription":"永历十五年，你做出了一个改变历史进程的决定——率军渡海收复台湾。你站在金门的料罗湾，面对茫茫大海，身后是两万五千名将士和数百艘战船。你的副将何斌向你进献了台湾水道图，帮助你制定了渡海作战计划。这是中国古代历史上最壮丽的海上远征之一。",
"npcDialogues":[{"speaker":"何斌","text":"国姓爷，这是台湾鹿耳门的水道图。大船要从这里进去，但水道很窄，只有涨潮时才能通过。","avatar":"何"},{"speaker":"部将","text":"国姓爷，渡海作战风险极大。将士们愿意追随您，但我们准备好了吗？","avatar":"将"}],"dialogues":[{"id":"d1","text":"台湾自古是中国领土，岂能让红毛番长期霸占？我决心收复台湾，为中国开辟新的天地！","speaker":"我","avatar":"成","score":95,"triggeredEvent":"决心收复","historicalNote":"郑成功在永历十五年率军渡海收复台湾，经过数月激战，最终驱逐荷兰殖民者，收复了中国领土台湾。这是中国历史上的重大事件。","consequence":"你毅然下令渡海东征。数万将士在数百艘战船上浩浩荡荡驶向台湾，开始了中国古代历史上最壮丽的海上远征之一。"},{"id":"d2","text":"何斌献上的水道图很关键。我们的舰队要利用涨潮时机，通过鹿耳门的狭窄水道，直插台湾腹地。","speaker":"我","avatar":"成","score":92,"triggeredEvent":"鹿耳门登陆","historicalNote":"郑成功利用何斌提供的水道图，趁涨潮时通过鹿耳门的狭窄水道成功登陆台湾。这是一个精妙的战术决策。","consequence":"你利用潮汐变化，率舰队通过鹿耳门的狭窄水道成功登陆台湾。荷兰人措手不及，惊呼这是天神相助。"},{"id":"d3","text":"将士们，台湾就在前方！此行虽有风险，但成功之后，我们就有了一个稳固的根据地！","speaker":"我","avatar":"成","score":85,"triggeredEvent":"鼓舞士气","historicalNote":"郑成功在渡海前发表了激昂的动员讲话，鼓舞了全军将士的士气。两万五千名将士斗志昂扬地踏上了征途。","consequence":"你的动员讲话极大地鼓舞了将士们的士气。全军上下一心，浩浩荡荡地驶向台湾。"},{"id":"d4","text":"渡海途中可能会遇到风暴和荷兰人的舰队拦截。我们要做好充分的准备。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"周密准备","historicalNote":"郑成功在渡海前做了周密的准备工作，包括选择正确的渡海时机、准备充足的补给和制定详细的作战计划。","consequence":"你做了周密的准备工作，选择了一个有利于渡海的天气窗口。舰队顺利出发，向台湾进发。"},{"id":"d5","text":"荷兰人的炮台防守严密，我们不能正面强攻。要利用夜色和潮汐的掩护，偷渡鹿耳门。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"偷渡战术","historicalNote":"郑成功确实利用夜色和潮汐的掩护，成功偷渡了荷兰人认为无法通过的鹿耳门水道。","consequence":"你在夜色和潮汐的掩护下，率领舰队巧妙地绕过了荷兰人的防线，成功登陆台湾。荷兰人大为震惊。"},{"id":"d6","text":"台湾的百姓是我们的同胞，我们收复台湾后一定要善待他们。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"善待百姓","historicalNote":"郑成功收复台湾后确实善待当地百姓，推行了有利于民生的政策，受到了台湾百姓的拥护。","consequence":"你告诫将士要善待台湾百姓，得到了当地原住民的欢迎和支持。百姓的帮助为你的军事行动提供了重要支援。"}],"nextActId":"act-5"},{"id":"act-5","title":"围困热兰遮","isKeyAct":True,"sceneDescription":"你成功登陆台湾后，荷兰人在台湾的据点只剩下热兰遮城。这座由荷兰人精心建造的城堡防守坚固，护城河和炮台让它看起来坚不可摧。你采取了长期围困的策略，切断了城内的水源和补给线。围城战持续了九个月，双方都在痛苦的煎熬中消耗。",
"npcDialogues":[{"speaker":"荷兰总督揆一","text":"郑成功的军队围得太紧了，我们的食物和弹药都快用完了。援军什么时候才能到？","avatar":"揆"},{"speaker":"部将","text":"国姓爷，城中荷兰人已经弹尽粮绝了。我们要不要发起最后的总攻？","avatar":"将"}],"dialogues":[{"id":"d1","text":"对热兰遮城要围而不攻，切断他们的水源和补给线。荷兰人撑不了多久就会投降！","speaker":"我","avatar":"成","score":90,"triggeredEvent":"围困策略","historicalNote":"郑成功对热兰遮城采取了围困策略，切断了城内的水源和海上补给线。这个策略最终迫使荷兰人投降。","consequence":"你下令围困热兰遮城，切断了所有补给线。荷兰人弹尽粮绝，援军迟迟未到。围城九个月后，荷兰人被迫谈判投降。"},{"id":"d2","text":"荷兰人的海上优势已经没有了，因为我们的水师控制了台湾海峡。他们断粮只是时间问题。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"控制海峡","historicalNote":"郑成功的水师控制了台湾海峡，切断了荷兰人的海上补给线。这是围困战略成功的关键因素之一。","consequence":"你派出水师控制了台湾海峡，荷兰人的海上补给线被彻底切断。城内的荷兰人陷入绝望。"},{"id":"d3","text":"城中传出荷兰人内部不和的消息。我们可以利用他们的分歧，加快投降进程。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"分化敌营","historicalNote":"热兰遮城内的荷兰人确实出现了内部分歧，有人主张投降，有人坚持抵抗。这种分歧加速了城池的陷落。","consequence":"你利用荷兰人的内部矛盾，通过传信和谈判加速了投降进程。城内的分裂越来越严重。"},{"id":"d4","text":"我已经做好了总攻的准备。如果荷兰人不投降，我们就用大炮轰开城门！","speaker":"我","avatar":"成","score":85,"triggeredEvent":"准备总攻","historicalNote":"郑成功确实在围城期间准备了总攻，从南北两面炮击热兰遮城。荷兰人在承受不了炮击后终于同意谈判。","consequence":"你在南北两面架设了大炮，对热兰遮城发起猛烈的炮击。荷兰人终于承受不住了，同意谈判投降。"},{"id":"d5","text":"我们要给荷兰人留一条体面的退路，这样才能让他们痛快地投降，减少不必要的伤亡。","speaker":"我","avatar":"成","score":83,"triggeredEvent":"体面受降","historicalNote":"郑成功在荷兰人投降时确实给予了一定的体面待遇，允许他们携带私人物品离开。这体现了他的政治智慧。","consequence":"你同意让荷兰人携带私人物品安全离开。这种宽容的态度让荷兰人痛快地签署了投降书。"},{"id":"d6","text":"台湾终于回到中国人手中了！我要在这里建立一个新的根据地，继续反清复明的大业！","speaker":"我","avatar":"成","score":92,"triggeredEvent":"收复台湾","historicalNote":"永历十五年十二月十三日，荷兰人在投降书上签字，结束了在台湾三十八年的殖民统治。郑成功收复台湾是中国历史上的重大事件。","consequence":"荷兰人正式投降，结束了在台湾三十八年的殖民统治。你收复了台湾，为中国开拓了一片新的天地。这一年，你三十九岁。"}],"nextActId":"act-6"},{"id":"act-6","title":"开台治台","isKeyAct":False,"sceneDescription":"收复台湾后，你立即着手治理这片土地。你废除了荷兰人的殖民统治制度，建立了一套完整的行政体系。你推行屯田制，鼓励大陆居民移民台湾，发展农业生产。在你的治理下，台湾从一个荒凉的殖民地变成了一个生机勃勃的新天地。",
"npcDialogues":[{"speaker":"部将","text":"国姓爷，台湾地广人稀，我们需要大量的劳动力来开发这片土地。","avatar":"将"},{"speaker":"台湾百姓","text":"郑大人的政策好，我们有了自己的土地，可以安心种田了！","avatar":"民"}],"dialogues":[{"id":"d1","text":"我要在台湾推行屯田制，让将士们一边守卫边疆一边发展农业。自给自足才能长期坚守。","speaker":"我","avatar":"成","score":90,"triggeredEvent":"推行屯田","historicalNote":"郑成功在台湾推行屯田制，不仅解决了军队的粮食问题，还促进了台湾的农业发展。这一政策对台湾的开发具有重要意义。","consequence":"你推行屯田制，将士们在戍守边疆的同时开垦荒地。台湾的农业迅速发展，粮食产量大幅提高。"},{"id":"d2","text":"我要鼓励大陆居民来台湾定居，带来先进的农业技术和文化。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"鼓励移民","historicalNote":"郑成功确实大力鼓励大陆居民移民台湾，这批移民带来了先进的农业技术和中原文化，极大地促进了台湾的发展。","consequence":"你颁布优惠政策吸引大陆居民来台定居。大量移民带来了先进的技术和文化，台湾的面貌日新月异。"},{"id":"d3","text":"我要建立府县制度，在台湾设立行政机构，有效管理各地。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"建立行政","historicalNote":"郑成功在台湾建立了行政管理体系，设立了一府两县，将台湾纳入了中国的地方行政体系。","consequence":"你在台湾建立了完善的行政体系，设立府县治理各地。台湾从殖民地正式变成了中国的一部分。"},{"id":"d4","text":"台湾的原住民是我们的同胞，我要尊重他们的习俗，与他们和平共处。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"善待原住民","historicalNote":"郑成功在台湾确实与当地原住民保持了较为和平的关系，尊重他们的土地权利和文化习俗。","consequence":"你善待台湾原住民，尊重他们的土地和文化。这种开明的民族政策赢得了原住民的信任和支持。"},{"id":"d5","text":"台湾的开发需要时间和耐心，我要从长计议，稳扎稳打。","speaker":"我","avatar":"成","score":80,"triggeredEvent":"长远规划","historicalNote":"郑成功在台湾的开发虽然时间不长，但他打下了坚实的基础。后来的清政府继续了他的开发政策。","consequence":"你制定了长远的发展规划，稳扎稳打地开发台湾。虽然你的时间有限，但打下的基础让台湾持续发展。"},{"id":"d6","text":"我在台湾也要兴办学校，让这里的孩子们都能读书识字，接受教育。","speaker":"我","avatar":"成","score":83,"triggeredEvent":"兴办学校","historicalNote":"郑成功在台湾确实注重教育事业，建立了学校推广儒学。这为台湾的文化发展奠定了基础。","consequence":"你在台湾兴办学校，推广儒学教育。台湾的文化水平在你的治理下迅速提高。"}],"nextActId":"act-7"},{"id":"act-7","title":"英年早逝","isKeyAct":False,"sceneDescription":"收复台湾仅一年多后，你在种种压力下病倒了。父亲被清朝杀害的消息传来，你悲痛欲绝。加上水土不服、军务繁重，你的身体急剧恶化。永历十六年五月，你在台湾病逝，年仅三十九岁。临终前，你面朝大海，朝着大陆的方向拱手而拜。",
"npcDialogues":[{"speaker":"郑经","text":"父亲！您不能走啊！台湾刚收复，百废待兴，我们还需要您啊！","avatar":"经"},{"speaker":"郑成功","text":"吾本欲克复中原，以报国恩。今中道而殂，天也。台湾虽小，但不可弃。你们要坚守到底！","avatar":"成"}],"dialogues":[{"id":"d1","text":"吾本欲克复中原，以报国恩。今中道而殂，天也。台湾虽小，但不可弃。儿辈们，一定要守住这块土地！","speaker":"我","avatar":"成","score":95,"triggeredEvent":"临终遗言","historicalNote":"郑成功临终前仍念念不忘反清复明的事业，同时叮嘱后人坚守台湾。'台湾虽小，但不可弃'成为他留给后人的最重要的遗训。","consequence":"你面朝大陆方向离世，年仅三十九岁。你的遗言激励了后人继续坚守台湾。郑经继承你的事业，继续经营台湾。"},{"id":"d2","text":"台湾是我心血的结晶，我死之后，你们一定要好好守住它。","speaker":"我","avatar":"成","score":92,"triggeredEvent":"守住台湾","historicalNote":"郑成功去世后，他的儿子郑经继续经营台湾，后来清政府在康熙年间统一台湾。但郑成功开台治台的功绩不可磨灭。","consequence":"你的儿子郑经继承了你的事业，继续经营台湾二十多年。你打下的基础让台湾持续发展。"},{"id":"d3","text":"父亲被清朝杀害的消息传来，我悲痛欲绝。不孝子未能保护父亲，这是我一生的遗憾。","speaker":"我","avatar":"成","score":80,"triggeredEvent":"父仇未报","historicalNote":"郑芝龙被清朝杀害的消息确实对郑成功造成了巨大的打击，这可能是加速他去世的重要原因之一。","consequence":"父亲的死讯让你悲痛万分，身体急剧恶化。你带着未能为父报仇的遗憾离开了人世。"},{"id":"d4","text":"我才三十九岁，还有那么多事情没做完……台湾的开发才刚刚开始。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"壮志未酬","historicalNote":"郑成功年仅三十九岁便英年早逝，收复台湾后仅一年多就去世了，许多开发台湾的计划未能实现。","consequence":"你带着壮志未酬的遗憾离去。台湾的开发才刚刚起步，你的离去让无数人扼腕叹息。"},{"id":"d5","text":"我的将士们跟着我出生入死，希望你们能善待他们，在台湾安居乐业。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"善待将士","historicalNote":"郑成功临终前确实嘱咐后人善待跟随他的将士和移民。这些人在台湾落地生根，成为开发台湾的重要力量。","consequence":"你的将士们在台湾安居乐业，他们的后代成为了台湾开发的重要力量。你的善后安排得当。"},{"id":"d6","text":"面朝大海，我虽然没能回到大陆，但我在台湾也留下了一段值得骄傲的历史。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"面向大海","historicalNote":"郑成功面朝大海而逝的情景成为后世最动人的画面之一。他虽然未能回到大陆，但在台湾留下了不朽的历史功绩。","consequence":"你面朝大海，拱手而拜。身后是你在台湾开拓的土地，前方是你魂牵梦绕的大陆。你的人生虽然短暂，但光芒万丈。"}],"nextActId":"act-8"},{"id":"act-8","title":"民族英雄","isKeyAct":False,"sceneDescription":"你去世后，你的事迹在两岸广泛传颂。后人尊你为'民族英雄'和'开台圣王'。你在短短三十九年的人生中，从金门誓师到收复台湾，完成了中国历史上最壮丽的篇章之一。你的名字永远镌刻在了中华民族的英雄史册上。",
"npcDialogues":[{"speaker":"郑经","text":"父亲，我会继续您的遗志，经营好台湾，绝不辜负您的期望。","avatar":"经"},{"speaker":"后人","text":"郑成功收复台湾，是中国历史上最伟大的爱国壮举之一。他的精神激励了后世无数仁人志士！","avatar":"后"}],"dialogues":[{"id":"d1","text":"我这一生虽然短暂，但没有虚度。收复台湾，是我为这个国家做的最大的贡献。","speaker":"我","avatar":"成","score":95,"triggeredEvent":"英雄永存","historicalNote":"郑成功被后世尊为'民族英雄'和'开台圣王'。他收复台湾的事迹是中国历史上最伟大的爱国壮举之一。","consequence":"你虽然英年早逝，但收复台湾的壮举让你永载史册。后世在台南为你建立了延平郡王祠，世世代代纪念你的功绩。"},{"id":"d2","text":"台湾的开发还要继续。我虽然走了，但我留下的基础足以支撑台湾的长远发展。","speaker":"我","avatar":"成","score":88,"triggeredEvent":"开发遗泽","historicalNote":"郑成功在台湾的开发虽然时间不长，但他建立的基础对台湾后来的发展产生了深远影响。","consequence":"你打下的基础让台湾持续发展。后来的清政府继承了你在台湾的治理体系，台湾逐渐成为中国东南沿海的重要省份。"},{"id":"d3","text":"我在海上征战一生，打败了荷兰人，收复了台湾。这些经历证明了：只要坚定信念，再强大的敌人也能战胜。","speaker":"我","avatar":"成","score":90,"triggeredEvent":"信念之力","historicalNote":"郑成功以弱胜强、驱逐荷兰殖民者的故事激励了后世无数人。他的精神在台湾、福建等地影响深远。","consequence":"你以弱胜强的壮举激励了后世无数人。在民族危难的时刻，人们总会想起你的名字和你的故事。"},{"id":"d4","text":"两岸的百姓都会记住我。台湾和大陆，本就是一家。","speaker":"我","avatar":"成","score":85,"triggeredEvent":"两岸记忆","historicalNote":"郑成功在两岸都有着崇高的地位。大陆和台湾都有纪念他的场所。他是连接两岸历史记忆的重要人物。","consequence":"你在两岸都有着崇高的地位，成为连接两岸历史记忆的重要人物。你的故事让两岸人民都感到骄傲。"},{"id":"d5","text":"我希望后人能从我的一生中学到：面对强敌不屈服，面对困难不放弃。","speaker":"我","avatar":"成","score":82,"triggeredEvent":"精神传承","historicalNote":"郑成功的爱国精神和不屈意志成为了中华民族精神财富的重要组成部分。他的事迹被编入教科书，代代相传。","consequence":"你的精神代代相传，成为中华民族精神财富的重要组成部分。你的故事激励了一代又一代的中国人。"},{"id":"d6","text":"开台圣王，民族英雄。这些称号对我来说都不重要。重要的是，我做了一个中国人应该做的事。","speaker":"我","avatar":"成","score":93,"triggeredEvent":"国姓爷永恒","historicalNote":"郑成功是中国历史上最伟大的民族英雄之一。他以三十九岁的短暂生命完成了收复台湾的壮举，被后世尊为'开台圣王'和'国姓爷'。","consequence":"你以三十九岁的壮年完成了不朽的功业。'国姓爷'——这个名字跨越了海峡，穿越了时间，永远铭刻在中华民族的史册上。"}],"nextActId":None}]}

files_to_write = {"junior-song-yuan-wentianxiang.json": wentianxiang, "junior-song-yuan-liqingzhao.json": liqingzhao, "junior-ming-qing-zhengchenggong.json": zhengchenggong}
for fname, data in files_to_write.items():
    path = os.path.join(base, fname)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"Written: {fname}")
